import type { StorybookConfig } from '@storybook/react-native-web-vite';
import type { PluginOption } from 'vite';
import { transformWithEsbuild } from 'vite';
import path from 'path';

const JSX_JS_PACKAGES = [
  'react-native-flip-card',
  '@semparar/design-system-app',
];

function jsxInJsPlugin(): PluginOption {
  return {
    name: 'storybook:jsx-in-js',
    enforce: 'pre',
    async transform(code, id) {
      const cleanId = id.replace(/\?.*$/, '');
      if (
        /\.js$/.test(cleanId) &&
        JSX_JS_PACKAGES.some(pkg => id.includes(pkg)) &&
        (code.includes('<') || code.includes('/>'))
      ) {
        return transformWithEsbuild(code, id, {
          loader: 'jsx',
          jsx: 'automatic',
        });
      }
    },
  };
}

const CJS_IN_ESM_PACKAGES = [
  'react-native-svg/lib/module/',
  'react-native-reanimated/lib/module/',
];

function dtsStubPlugin(): PluginOption {
  return {
    name: 'storybook:dts-stub',
    enforce: 'pre',
    resolveId(source, importer) {
      if (!importer?.includes('@semparar/')) return;
      const cleanImporter = importer.replace(/\?.*$/, '');
      const cleanSource = source.replace(/\?.*$/, '');
      const dir = path.dirname(cleanImporter);

      if (cleanSource.endsWith('.d') || cleanSource.endsWith('.d.ts')) {
        const absPath =
          cleanSource.startsWith('.') || !cleanSource.startsWith('/')
            ? path.resolve(dir, cleanSource)
            : cleanSource;
        const dtsPath = absPath.endsWith('.d.ts')
          ? absPath
          : absPath + '.ts';
        return `\0dts-stub:${dtsPath}`;
      }

      if (
        cleanImporter.includes('node_modules/@semparar/') &&
        !cleanSource.startsWith('\0') &&
        (cleanSource.startsWith('.') || cleanSource.startsWith('/'))
      ) {
        const candidate = path.resolve(dir, cleanSource);
        const dtsCandidate = candidate + '.d.ts';
        try {
          require('fs').accessSync(dtsCandidate);
          return `\0dts-stub:${dtsCandidate}`;
        } catch {
          // not a .d.ts, let Vite handle it normally
        }
      }
    },
    load(id) {
      if (!id.startsWith('\0dts-stub:')) return;
      const realPath = id.replace('\0dts-stub:', '');
      try {
        const fs = require('fs');
        const filePath = realPath.endsWith('.d.ts')
          ? realPath
          : realPath + '.d.ts';
        const src = fs.readFileSync(filePath, 'utf-8');
        const names = [
          ...src.matchAll(
            /export\s+(?:interface|type|const|function|class|enum)\s+(\w+)/g,
          ),
        ].map(m => m[1]);
        if (names.length) {
          return names
            .map(n => `export const ${n} = {};`)
            .concat(['export default {};'])
            .join('\n');
        }
      } catch {
        // file not readable, fall through to default stub
      }
      return 'export default {};';
    },
  };
}

function circularFixPlugin(): PluginOption {
  return {
    name: 'storybook:circular-fix',
    enforce: 'pre',
    resolveId(source, importer) {
      if (
        importer?.includes('CardOptionDrag/view.tsx') &&
        source === './view.group'
      ) {
        return '\0circular-stub:CardOptionDragGroup';
      }
    },
    load(id) {
      if (id === '\0circular-stub:CardOptionDragGroup') {
        return 'export default function CardOptionDragGroup() { return null; }';
      }
    },
  };
}

function cjsToEsmPlugin(): PluginOption {
  return {
    name: 'storybook:cjs-to-esm',
    enforce: 'pre',
    transform(code, id) {
      const cleanId = id.replace(/\?.*$/, '');
      if (
        !(/\.js$/.test(cleanId) && code.includes('module.exports')) ||
        !CJS_IN_ESM_PACKAGES.some(pkg => cleanId.includes(pkg))
      ) {
        return;
      }

      const objMatch = code.match(/module\.exports\s*=\s*\{([^}]+)\}/);
      if (objMatch) {
        const isIdentifier = /^[a-zA-Z_$][a-zA-Z0-9_$]*$/;
        const entries = objMatch[1]
          .split(',')
          .map(e => e.trim())
          .filter(Boolean)
          .filter(e => {
            const parts = e.split(':').map(p => p.trim());
            return parts.every(p => isIdentifier.test(p));
          })
          .map(e => {
            const parts = e.split(':').map(p => p.trim());
            if (parts.length === 2 && parts[0] !== parts[1]) {
              return `export { ${parts[1]} as ${parts[0]} };`;
            }
            return `export { ${parts[0]} };`;
          });
        const exportsBlock = entries.join('\n');
        return code
          .replace(/["']use strict["'];?\s*/, '')
          .replace(/module\.exports\s*=\s*\{[^}]+\};?/, exportsBlock);
      }

      const simpleMatch = code.match(
        /module\.exports\s*=\s*([a-zA-Z_$][a-zA-Z0-9_$]*|null|undefined|\d+|'[^']*'|"[^"]*");?/,
      );
      if (simpleMatch) {
        const value = simpleMatch[1];
        const basename = cleanId
          .replace(/^.*\//, '')
          .replace(/\.(web|native)?\.js$/, '');
        const namedExport =
          basename && /^[a-zA-Z_$]/.test(basename)
            ? `export const ${basename} = ${value};\n`
            : '';
        return code
          .replace(/["']use strict["'];?\s*/, '')
          .replace(
            simpleMatch[0],
            `${namedExport}export default ${value};`,
          );
      }
    },
  };
}

const config: StorybookConfig = {
  stories: ['../src/**/*.stories.@(ts|tsx)'],

  staticDirs: [
    // Ubuntu fonts from design system (Ubuntu-*.ttf)
    {
      from: '../node_modules/@semparar/design-system-app/src/assets/fonts',
      to: '/fonts',
    },
    // Icon fonts (IconsSemParar, icomoon) + other local fonts — overrides DS on name collision
    {
      from: '../src/assets/fonts',
      to: '/fonts',
    },
  ],

  framework: {
    name: '@storybook/react-native-web-vite',
    options: {
      modulesToTranspile: [
        'react-native',
        'react-native-reanimated',
        'react-native-safe-area-context',
        'react-native-gesture-handler',
        'react-native-icomoon',
        'react-native-flip-card',
        'react-native-linear-gradient',
        'react-native-status-bar-height',
        'react-native-svg',
        'react-native-svg-charts',
        '@semparar/design-system-app',
      ],
    },
  },

  addons: ['@storybook/addon-essentials'],

  viteFinal: async config => {
    config.plugins = config.plugins || [];
    config.plugins.push(dtsStubPlugin());
    config.plugins.push(circularFixPlugin());
    config.plugins.push(jsxInJsPlugin());
    config.plugins.push(cjsToEsmPlugin());

    config.optimizeDeps = config.optimizeDeps || {};
    config.optimizeDeps.include = [
      ...(config.optimizeDeps.include || []),
      'styled-components',
      'styled-components/native',
      'card-validator',
      'credit-card-type',
      'lodash',
      'xdate',
      'invariant',
      'fbjs',
      'hoist-non-react-statics',
      'prop-types',
      'object-assign',
      'shallowequal',
      'moment',
    ];

    config.resolve = config.resolve || {};
    config.resolve.alias = {
      ...(config.resolve.alias || {}),
      '~': path.resolve(__dirname, '../src'),
      '~/store': path.resolve(__dirname, 'mocks/store.ts'),
      'postcss': path.resolve(__dirname, '../node_modules/postcss/lib/postcss.mjs'),
      'react-native-linear-gradient': path.resolve(
        __dirname,
        'mocks/react-native-linear-gradient.tsx',
      ),
      'react-native-modalize': path.resolve(
        __dirname,
        'mocks/react-native-modalize.tsx',
      ),
      'react-native-skeleton-placeholder': path.resolve(
        __dirname,
        'mocks/react-native-skeleton-placeholder.tsx',
      ),
      '@react-native-community/slider': path.resolve(
        __dirname,
        'mocks/react-native-community-slider.tsx',
      ),
      'lottie-react-native': path.resolve(
        __dirname,
        'mocks/lottie-react-native.tsx',
      ),
      'react-native-video': path.resolve(
        __dirname,
        'mocks/react-native-video.tsx',
      ),
      '@react-native/assets-registry/registry': path.resolve(
        __dirname,
        'mocks/react-native-assets-registry.tsx',
      ),
      'deprecated-react-native-prop-types': path.resolve(
        __dirname,
        'mocks/deprecated-react-native-prop-types.tsx',
      ),
    };
    return config;
  },
};

export default config;

