import { useChannel } from 'storybook/internal/preview-api';
import type { SDUIScreen } from '../../../src/services/sdui/models';
import { EVENTS } from './constants';

export function useSDUIJsonEditor(defaultScreen: SDUIScreen): SDUIScreen {
  const [screen, setScreen] = useState<SDUIScreen>(defaultScreen);

  const emit = useChannel({
    [EVENTS.UPDATE_JSON]: (json: SDUIScreen) => {
      setScreen(json);
    },
    [EVENTS.REQUEST_DEFAULT]: () => {
      emit(EVENTS.SET_DEFAULT_JSON, JSON.stringify(defaultScreen, null, 2));
    },
