import { useEffect, useRef, useState } from 'react';
import { addons } from 'storybook/internal/preview-api';
import type { SDUIScreen } from '../../../src/services/sdui/models';
import { EVENTS } from './constants';

export function useSDUIJsonEditor(defaultScreen: SDUIScreen): SDUIScreen {
  const [screen, setScreen] = useState<SDUIScreen>(defaultScreen);
  const defaultRef = useRef(defaultScreen);
  defaultRef.current = defaultScreen;

  useEffect(() => {
    setScreen(defaultScreen);
  }, [defaultScreen]);

  useEffect(() => {
    const channel = addons.getChannel();

    const onUpdate = (json: SDUIScreen) => {
      setScreen(json);
    };

    const onRequestDefault = () => {
      channel.emit(
        EVENTS.SET_DEFAULT_JSON,
        JSON.stringify(defaultRef.current, null, 2),
      );
    };

    channel.on(EVENTS.UPDATE_JSON, onUpdate);
    channel.on(EVENTS.REQUEST_DEFAULT, onRequestDefault);

    channel.emit(
      EVENTS.SET_DEFAULT_JSON,
      JSON.stringify(defaultRef.current, null, 2),
    );

    return () => {
      channel.off(EVENTS.UPDATE_JSON, onUpdate);
      channel.off(EVENTS.REQUEST_DEFAULT, onRequestDefault);
    };
  }, []);

  return screen;
}

