import React, { useCallback, useEffect, useRef, useState } from 'react';
import { useChannel, useStorybookState } from 'storybook/internal/manager-api';
import { EVENTS } from './constants';
import { useIndexedDB } from './useIndexedDB';

function idbKeyFor(storyId: string) {
  return `sdui-json-${storyId}`;
}

export function JsonEditorPanel() {
  const state = useStorybookState();
  const storyId = state.storyId ?? '';

  const [defaultJson, setDefaultJson] = useState<string>('');
  const [text, setText] = useState<string>('');
  const [error, setError] = useState<string | null>(null);
  const [dirty, setDirty] = useState(false);
  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const { stored, save, remove, ready } = useIndexedDB(idbKeyFor(storyId));

  const emit = useChannel({
    [EVENTS.SET_DEFAULT_JSON]: (json: string) => {
      setDefaultJson(json);
    },
  });

  useEffect(() => {
    emit(EVENTS.REQUEST_DEFAULT);
  }, [storyId, emit]);

  useEffect(() => {
    if (!ready || !defaultJson) return;
    const initial = stored ?? defaultJson;
    setText(initial);
    setDirty(!!stored);
    setError(null);
  }, [ready, stored, defaultJson, storyId]);

  const handleChange = useCallback(
    (value: string) => {
      setText(value);
      setError(null);

      if (debounceRef.current) clearTimeout(debounceRef.current);

      debounceRef.current = setTimeout(() => {
        try {
          const parsed = JSON.parse(value);
          save(value);
          setDirty(true);
          emit(EVENTS.UPDATE_JSON, parsed);
        } catch (e) {
          setError((e as Error).message);
        }
      }, 400);
    },
    [emit, save],
  );

  const handleReset = useCallback(() => {
    remove();
    setText(defaultJson);
    setDirty(false);
    setError(null);
    try {
      emit(EVENTS.UPDATE_JSON, JSON.parse(defaultJson));
    } catch { /* noop */ }
  }, [defaultJson, emit, remove]);

  const handleFormat = useCallback(() => {
    try {
      const parsed = JSON.parse(text);
      const formatted = JSON.stringify(parsed, null, 2);
      setText(formatted);
      save(formatted);
      emit(EVENTS.UPDATE_JSON, parsed);
      setError(null);
    } catch (e) {
      setError((e as Error).message);
    }
  }, [text, emit, save]);

  if (!storyId) {
    return <div style={styles.empty}>Select a story to edit its JSON.</div>;
  }

  return (
    <div style={styles.container}>
      <div style={styles.toolbar}>
        <span style={styles.label}>
          SDUI JSON {dirty && <span style={styles.badge}>edited</span>}
        </span>
        <div style={styles.actions}>
          <button style={styles.btn} onClick={handleFormat}>
            Format
          </button>
          <button
            style={{ ...styles.btn, ...styles.btnReset }}
            onClick={handleReset}
            disabled={!dirty}
          >
            Reset
          </button>
        </div>
      </div>

      {error && <div style={styles.error}>JSON Error: {error}</div>}

      <textarea
        style={styles.textarea}
        value={text}
        onChange={e => handleChange(e.target.value)}
        spellCheck={false}
      />
    </div>
  );
}

const styles: Record<string, React.CSSProperties> = {
  container: {
    display: 'flex',
    flexDirection: 'column',
    height: '100%',
    fontFamily: 'monospace',
    fontSize: 12,
  },
  toolbar: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    padding: '6px 10px',
    borderBottom: '1px solid #e0e0e0',
    background: '#fafafa',
  },
  label: {
    fontWeight: 600,
    fontSize: 13,
    color: '#333',
  },
  badge: {
    display: 'inline-block',
    marginLeft: 6,
    padding: '1px 6px',
    borderRadius: 4,
    background: '#ff9800',
    color: '#fff',
    fontSize: 10,
    fontWeight: 700,
  },
  actions: {
    display: 'flex',
    gap: 6,
  },
  btn: {
    padding: '4px 10px',
    borderRadius: 4,
    border: '1px solid #ccc',
    background: '#fff',
    cursor: 'pointer',
    fontSize: 12,
  },
  btnReset: {
    borderColor: '#ff5722',
    color: '#ff5722',
  },
  error: {
    padding: '6px 10px',
    background: '#ffebee',
    color: '#c62828',
    fontSize: 12,
    borderBottom: '1px solid #ef9a9a',
  },
  textarea: {
    flex: 1,
    resize: 'none',
    border: 'none',
    outline: 'none',
    padding: 10,
    fontFamily: "'Ubuntu Mono', 'Menlo', 'Monaco', 'Consolas', monospace",
    fontSize: 12,
    lineHeight: '1.5',
    background: '#fafafa',
    color: '#1a1a2e',
    tabSize: 2,
  },
  empty: {
    padding: 20,
    color: '#999',
    textAlign: 'center',
  },
};

