const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage({ viewport: { width: 1400, height: 900 } });

  const logs = [];
  page.on('console', msg => logs.push(msg.type() + ': ' + msg.text()));

  await page.goto('http://localhost:6006/?path=/story/sdui-voucherdemo--form');
  await page.waitForTimeout(5000);

  // Click JSON Editor tab
  await page.locator('button[role=\"tab\"]:has-text(\"JSON Editor\")').click();
  await page.waitForTimeout(1000);

  // Get the textarea
  const textarea = page.locator('textarea');
  const currentJson = await textarea.inputValue();

  // Replace the heading title
  const modified = currentJson.replace(
    'Defina o desconto para seu abastecimento',
    'LIVE EDIT WORKS!'
  );

  // Clear and type to trigger React onChange
  await textarea.click();
  await textarea.selectText();
  await textarea.press('Backspace');
  await textarea.fill(modified);

  // Wait for debounce (400ms) + extra
  await page.waitForTimeout(2000);

  // Check iframe for the edited text
  const iframe = page.frameLocator('#storybook-preview-iframe');
  const texts = await iframe.locator('[dir=\"auto\"]').allTextContents();
  const found = texts.some(t => t.includes('LIVE EDIT'));
  console.log('Live edit reflected in preview:', found);
  console.log('Texts found:', texts.join(' | ').substring(0, 500));

  // Check for channel-related errors  
  const channelLogs = logs.filter(l => l.includes('channel') || l.includes('emit') || l.includes('error'));
  channelLogs.forEach(l => console.log(l.substring(0, 200)));

  await browser.close();
})();
