const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage({ viewport: { width: 1400, height: 900 } });

  await page.goto('http://localhost:6006/?path=/story/sdui-voucherdemo--form');
  await page.waitForTimeout(5000);

  // Click JSON Editor tab
  await page.locator('button[role=\"tab\"]:has-text(\"JSON Editor\")').click();
  await page.waitForTimeout(1000);

  // Get the textarea content and modify it
  const textarea = page.locator('textarea');
  const currentJson = await textarea.inputValue();
  const modified = currentJson.replace(
    'Defina o desconto para seu abastecimento',
    'LIVE EDIT WORKS!'
  );

  // Use evaluate to set value and trigger React onChange
  await textarea.evaluate((el, val) => {
    const nativeInputValueSetter = Object.getOwnPropertyDescriptor(window.HTMLTextAreaElement.prototype, 'value').set;
    nativeInputValueSetter.call(el, val);
    el.dispatchEvent(new Event('input', { bubbles: true }));
    el.dispatchEvent(new Event('change', { bubbles: true }));
  }, modified);

  // Wait for debounce
  await page.waitForTimeout(2000);

  // Screenshot
  await page.screenshot({ path: '.storybook/screenshots/json-editor-live-edit-v2.png', fullPage: false });

  // Check iframe
  const iframe = page.frameLocator('#storybook-preview-iframe');
  const previewText = await iframe.locator('body').textContent();
  console.log('Has LIVE EDIT:', previewText?.includes('LIVE EDIT'));

  await browser.close();
})();
